import pytest
from solution import Counter

@pytest.fixture
def counter():
    return Counter()

def test_starts_at_zero(counter):
    assert counter.value == 0

def test_increment_adds_one(counter):
    counter.increment()
    assert counter.value == 1

def test_increments_compound(counter):
    counter.increment()
    counter.increment()
    counter.increment()
    assert counter.value == 3

def test_fixture_is_fresh_per_test(counter):
    # If the fixture were session-scoped, this test would see count > 0
    # because the previous tests incremented. Default scope is function,
    # so each test gets a fresh Counter.
    assert counter.value == 0

options:
Each layer is a separate fixture; later layers declare earlier ones as parameters. pytest resolves the graph deepest-first.

```python
@pytest.fixture
def db():
    return connect()

@pytest.fixture
def db_session(db):
    return db.session()

@pytest.fixture
def repo(db_session):
    return Repo(db_session)
```

A test asking for `repo` triggers the whole chain; a test asking for just `db` gets only `db`. Each layer is reusable in isolation.

