cards.solution_code:
class Resource:
    open_count = 0

    def __init__(self):
        Resource.open_count += 1

    def close(self):
        if Resource.open_count > 0:
            Resource.open_count -= 1

    @classmethod
    def reset(cls):
        cls.open_count = 0

