import pytest
from solution import Resource

@pytest.fixture(autouse=True)
def reset_resource_state():
    Resource.reset()
    yield

@pytest.fixture
def resource():
    r = Resource()
    yield r
    r.close()

def test_resource_is_open_during_test(resource):
    assert Resource.open_count == 1

def test_resource_was_closed_after_previous_test():
    # Without the yield-finalizer in the `resource` fixture, this would be 1
    # (the previous test would have leaked an open Resource).
    assert Resource.open_count == 0

def test_double_close_safe(resource):
    resource.close()
    resource.close()
    assert Resource.open_count == 0

